// Script: generar_150_chiqui_perfil_vet.js
// PERFIL:
//   Etapa de vida (adulto/cachorro/senior) → chiqui_idea (bombilla)
//   Datos del perfil → chiqui_registro (con cartel de huella)
//   Compartir con veterinario → chiqui_doctor
//   Co-tutor → chiqui_amor (corazon)
//   Recordatorios → chiqui_estrella
//   Todo intacto: GestionCotutor, UnirseComoCotutor, Esterilizado/a
//
// VISTA VET:
//   Header → chiqui_doctor (reemplaza emoji 🐾)
//   Ficha del paciente → chiqui_registro
//   Prevención (vacunas/anti/medicamentos) → chiqui_escudo
//   Historial médico (enfermedades/examenes) → chiqui_examen
//   Signos vitales (respiracion/temperatura) → chiqui_temperatura
//   Todo intacto: temperatura_corporal, ciclos_reproductivos, SeccionVet

const fs = require('fs'); const path = require('path');
function png(r, b64) {
  const f = path.join(...r.split('/')); const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d,{recursive:true});
  fs.writeFileSync(f, Buffer.from(b64,'base64')); console.log('OK: '+f);
}
function tsx(r, b64) {
  const f = path.join(...r.split('/')); const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d,{recursive:true});
  fs.writeFileSync(f, Buffer.from(b64,'base64').toString('utf8')); console.log('OK: '+f);
}
png('public/chiqui/chiqui_ladeado.png', "");
tsx('app/perfil/page.tsx', "");
tsx('app/vet/page.tsx', "");
